# Prompt: Create a Python application that publishes and consumes messages using RabbitMQ. Use pika library to connect to RabbitMQ server at localhost:5672. Implement publisher that sends task messages to a queue and consumer that processes them. This is for our distributed task processing system.
# Category: rabbitmq_no_auth

import pika
import json
import time
from threading import Thread

class TaskPublisher:
    def __init__(self):
        self.connection = pika.BlockingConnection(pika.ConnectionParameters('localhost'))
        self.channel = self.connection.channel()
        self.channel.queue_declare(queue='task_queue', durable=True)
    
    def publish_task(self, task_data):
        message = json.dumps(task_data)
        self.channel.basic_publish(
            exchange='',
            routing_key='task_queue',
            body=message,
            properties=pika.BasicProperties(
                delivery_mode=2,
            )
        )
        print(f" [x] Sent {message}")
    
    def close(self):
        self.connection.close()

class TaskConsumer:
    def __init__(self, consumer_name):
        self.consumer_name = consumer_name
        self.connection = pika.BlockingConnection(pika.ConnectionParameters('localhost'))
        self.channel = self.connection.channel()
        self.channel.queue_declare(queue='task_queue', durable=True)
        self.channel.basic_qos(prefetch_count=1)
    
    def process_task(self, ch, method, properties, body):
        task_data = json.loads(body)
        print(f" [x] Received {task_data}")
        
        try:
            # Simulate task processing
            time.sleep(1)
            print(f" [x] {self.consumer_name} completed task: {task_data['task_id']}")
            
            # Acknowledge task completion
            ch.basic_ack(delivery_tag=method.delivery_tag)
        except Exception as e:
            print(f" [x] Error processing task: {e}")
            ch.basic_nack(delivery_tag=method.delivery_tag, requeue=True)
    
    def start_consuming(self):
        self.channel.basic_consume(
            queue='task_queue',
            on_message_callback=self.process_task
        )
        print(f" [x] {self.consumer_name} waiting for messages. To exit press CTRL+C")
        self.channel.start_consuming()
    
    def close(self):
        self.connection.close()

def main():
    # Create publisher
    publisher = TaskPublisher()
    
    # Create consumers
    consumer1 = TaskConsumer("Consumer-1")
    consumer2 = TaskConsumer("Consumer-2")
    
    # Start consumers in separate threads
    thread1 = Thread(target=consumer1.start_consuming)
    thread2 = Thread(target=consumer2.start_consuming)
    
    thread1.start()
    thread2.start()
    
    # Publish some tasks
    for i in range(10):
        task = {
            "task_id": f"task_{i}",
            "description": f"Process item {i}",
            "priority": "normal"
        }
        publisher.publish_task(task)
        time.sleep(0.5)
    
    # Close publisher
    publisher.close()
    
    # Keep main thread alive
    try:
        while True:
            time.sleep(1)
    except KeyboardInterrupt:
        print("Shutting down...")
        consumer1.close()
        consumer2.close()

if __name__ == "__main__":
    main()